// frontend/src/pages/ProfilePage.js
import { useState, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import api from '../api/axios';
import '../App.css'; // Create this CSS file

function ProfilePage() {
  const { user, setUser, logout } = useAuth();
  const fileInputRef = useRef(null);
  const [formData, setFormData] = useState({
    name: user?.name || '',
    bio: user?.bio || '',
    currentPassword: '',
    newPassword: '',
    confirmPassword: '',
  });
  const [profilePicture, setProfilePicture] = useState(user?.profilePicture || null);
  const [previewUrl, setPreviewUrl] = useState(user?.profilePicture || '/default-avatar.png');
  const [uploading, setUploading] = useState(false);
  const [message, setMessage] = useState('');
  const [error, setError] = useState('');

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleFileSelect = (e) => {
    const file = e.target.files[0];
    if (file) {
      // Validate file type
      if (!file.type.match(/image\/(jpeg|jpg|png|gif)/)) {
        setError('Please select a valid image file (JPEG, PNG, or GIF)');
        return;
      }
      
      // Validate file size (max 5MB)
      if (file.size > 5 * 1024 * 1024) {
        setError('Image size should be less than 5MB');
        return;
      }

      setProfilePicture(file);
      setPreviewUrl(URL.createObjectURL(file));
      setError('');
    }
  };

  const handleUploadProfilePicture = async () => {
    if (!profilePicture) return;

    setUploading(true);
    setError('');
    setMessage('');

    const formData = new FormData();
    formData.append('profilePicture', profilePicture);

    try {
      const res = await api.post('/auth/profile-picture', formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      });
      
      setUser({ ...user, profilePicture: res.data.profilePicture });
      setMessage('Profile picture updated successfully');
      
      // Clear the file input
      if (fileInputRef.current) {
        fileInputRef.current.value = '';
      }
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to upload profile picture');
    } finally {
      setUploading(false);
    }
  };

  const handleUpdateProfile = async (e) => {
    e.preventDefault();
    setError('');
    setMessage('');
    try {
      const res = await api.put('/auth/profile', {
        name: formData.name,
        bio: formData.bio,
      });
      setUser(res.data);
      setMessage('Profile updated successfully');
    } catch (err) {
      setError(err.response?.data?.message || 'Update failed');
    }
  };

  const handleChangePassword = async (e) => {
    e.preventDefault();
    if (formData.newPassword !== formData.confirmPassword) {
      setError('Passwords do not match');
      return;
    }
    try {
      await api.put('/auth/change-password', {
        currentPassword: formData.currentPassword,
        newPassword: formData.newPassword,
      });
      setMessage('Password changed successfully');
      setFormData({ ...formData, currentPassword: '', newPassword: '', confirmPassword: '' });
    } catch (err) {
      setError(err.response?.data?.message || 'Password change failed');
    }
  };

  return (
    <>
      <main className="container profile-page">
        <h1 className="profile-title">My Profile</h1>
        
        {message && <div className="alert alert-success">{message}</div>}
        {error && <div className="alert alert-error">{error}</div>}

        {/* Profile Picture Section */}
        <section className="profile-picture-section">
          <h2>Profile Picture</h2>
          <div className="profile-picture-container">
            <img 
              src={previewUrl} 
              alt="Profile" 
              className="profile-picture-large"
              onError={(e) => {
                e.target.src = '/default-avatar.png';
              }}
            />
            
            <div className="profile-picture-upload">
              <input
                type="file"
                ref={fileInputRef}
                onChange={handleFileSelect}
                accept="image/jpeg,image/png,image/gif"
                className="file-input"
                id="profile-picture-input"
              />
              <label htmlFor="profile-picture-input" className="btn btn-secondary">
                Choose Image
              </label>
              
              {profilePicture && (
                <button 
                  onClick={handleUploadProfilePicture}
                  className="btn btn-primary"
                  disabled={uploading}
                >
                  {uploading ? 'Uploading...' : 'Upload Picture'}
                </button>
              )}
            </div>
            
            <p className="file-info">Supported: JPG, PNG, GIF (Max 5MB)</p>
          </div>
        </section>

        {/* Update Profile Section */}
        <section className="profile-section">
          <h2>Update Profile</h2>
          <form onSubmit={handleUpdateProfile} className="profile-form">
            <div className="form-group">
              <label htmlFor="name">Name</label>
              <input 
                type="text" 
                id="name"
                name="name" 
                value={formData.name} 
                onChange={handleChange} 
                required 
                className="form-input"
              />
            </div>
            
            <div className="form-group">
              <label htmlFor="bio">Bio</label>
              <textarea 
                id="bio"
                name="bio" 
                value={formData.bio} 
                onChange={handleChange} 
                rows="4"
                className="form-textarea"
                placeholder="Tell us about yourself..."
              />
            </div>
            
            <div className="form-group">
              <label htmlFor="email">Email (cannot be changed)</label>
              <input 
                type="email" 
                id="email"
                value={user?.email || ''} 
                disabled 
                className="form-input disabled"
              />
            </div>
            
            <button type="submit" className="btn btn-primary">Update Profile</button>
          </form>
        </section>

        {/* Change Password Section */}
        <section className="profile-section">
          <h2>Change Password</h2>
          <form onSubmit={handleChangePassword} className="profile-form">
            <div className="form-group">
              <label htmlFor="currentPassword">Current Password</label>
              <input 
                type="password" 
                id="currentPassword"
                name="currentPassword" 
                value={formData.currentPassword} 
                onChange={handleChange} 
                required 
                className="form-input"
              />
            </div>
            
            <div className="form-group">
              <label htmlFor="newPassword">New Password</label>
              <input 
                type="password" 
                id="newPassword"
                name="newPassword" 
                value={formData.newPassword} 
                onChange={handleChange} 
                required 
                className="form-input"
              />
            </div>
            
            <div className="form-group">
              <label htmlFor="confirmPassword">Confirm New Password</label>
              <input 
                type="password" 
                id="confirmPassword"
                name="confirmPassword" 
                value={formData.confirmPassword} 
                onChange={handleChange} 
                required 
                className="form-input"
              />
            </div>
            
            <button type="submit" className="btn btn-primary">Change Password</button>
          </form>
        </section>

        <button onClick={logout} className="btn btn-danger logout-btn">Logout</button>
      </main>
      
      <footer className="site-footer">
        <div className="container footer-container">
          <div className="footer-info">
